 27	  healthStatus: ThresholdStatus;
 28	  mTLS?: number;
 29	  node: TrafficNode;
 30	  protocol: string;
 31	  trafficPercentSuccess: string;
 32	  trafficRate: string;
 33	}
 34	
 35	type ReduxProps = {
 36	  kiosk: string;
 37	};
 38	
 39	type TrafficListComponentProps = ReduxProps &
 40	  FilterComponent.Props<TrafficListItem> & {
 41	    trafficItems: TrafficItem[];
 42	  };
 43	
 44	type TrafficListComponentState = FilterComponent.State<TrafficListItem>;
 45	
 46	const columns = (isMultiCluster: boolean): SortableTh[] => {
 47	  const cols: SortableTh[] = [
 48	    {
 49	      title: 'Status',
 50	      sortable: true,
 51	      width: 15
 52	    },
 53	    {
 54	      title: 'Name',
 55	      sortable: true,
 56	      width: 30
 57	    },
 58	    {
 59	      title: 'Rate',
 60	      sortable: true,
 61	      width: 10
 62	    },
 63	    {
 64	      title: 'Percent Success',
 65	      sortable: true,
 66	      width: 20
 67	    },
 68	    {
 69	      title: 'Protocol',
 70	      sortable: true,
 71	      width: 15
 72	    },
 73	    {
 74	      title: 'Actions',
 75	      sortable: false
 76	    }
 77	  ];
 78	
 79	  if (isMultiCluster) {
 80	    cols.splice(2, 0, {
 81	      title: 'Cluster',
 82	      sortable: true,
 83	      width: 15
 84	    });
 85	  }
 86	
 87	  return cols;
 88	};
 89	
 90	const LockIcon = (props: { mTLS?: number }): React.ReactElement => {
 91	  const msg = props.mTLS ? `${props.mTLS} % of mTLS traffic` : 'mTLS is disabled';
 92	
 93	  return (
 94	    <Tooltip position={TooltipPosition.top} content={msg}>
 95	      <>
 96	        {props.mTLS ? (
 97	          <KialiIcon.MtlsLock className={lockIconStyle} />
 98	        ) : (
 99	          <KialiIcon.MtlsUnlock className={lockIconStyle} />
100	        )}
101	      </>
102	    </Tooltip>
103	  );
104	};
105	
106	// Style constants
107	const containerStyle = kialiStyle({ padding: '1.25rem' });
108	const lockIconStyle = kialiStyle({ marginLeft: '0.25rem' });
