110	class TrafficList extends FilterComponent.Component<
111	  TrafficListComponentProps,
112	  TrafficListComponentState,
113	  TrafficListItem
114	> {
115	  constructor(props: TrafficListComponentProps) {
116	    super(props);
117	    this.state = {
118	      currentSortField: props.currentSortField,
119	      isSortAscending: props.isSortAscending,
120	      listItems: this.trafficToListItems(props.trafficItems)
121	    };
122	  }
123	
124	  componentDidMount(): void {
125	    // ensure the initial sort is applied
126	    this.sortItemList(this.state.listItems, this.state.currentSortField, this.state.isSortAscending);
127	  }
128	
129	  componentDidUpdate(prevProps: TrafficListComponentProps): void {
130	    // we only care about new TrafficItems, sorting is managed locally after initial render
131	    if (prevProps.trafficItems !== this.props.trafficItems) {
132	      const listItems = this.trafficToListItems(this.props.trafficItems);
133	
134	      this.setState({
135	        listItems: this.sortItemList(listItems, this.state.currentSortField, this.state.isSortAscending)
136	      });
137	    }
138	  }
139	
140	  render(): React.ReactNode {
141	    const cols = columns(isMultiCluster);
142	    const inboundRows = this.rows('inbound');
143	    const outboundRows = this.rows('outbound');
144	    const hasInbound = inboundRows.length > 0;
145	    const hasOutbound = outboundRows.length > 0;
146	    const sortIndex = sortFields.findIndex(sf => sf.id === this.state.currentSortField.id);
147	    const sortDirection = this.state.isSortAscending ? SortByDirection.asc : SortByDirection.desc;
148	    const sortBy = { index: sortIndex, direction: sortDirection };
149	
150	    return (
151	      <>
152	        <div className={containerStyle}>
153	          <Title headingLevel="h5" size={TitleSizes.lg}>
154	            {hasInbound ? '' : 'No '} Inbound Traffic
155	          </Title>
156	
157	          {hasInbound && (
158	            <SimpleTable
159	              label="Inbound Traffic List"
160	              columns={cols}
161	              rows={inboundRows}
162	              sortBy={sortBy}
163	              onSort={this.onSort}
164	            />
165	          )}
166	        </div>
167	
168	        <div className={containerStyle}>
169	          <Title headingLevel="h5" size={TitleSizes.lg}>
170	            {hasOutbound ? '' : 'No '} Outbound Traffic
171	          </Title>
172	
173	          {hasOutbound && (
174	            <SimpleTable
175	              label="Outbound Traffic List"
176	              columns={cols}
177	              rows={outboundRows}
178	              sortBy={sortBy}
179	              onSort={this.onSort}
180	            />
181	          )}
182	        </div>
183	      </>
184	    );
185	  }
186	
187	  // abstract FilterComponent.updateListItems
188	  updateListItems(): void {
189	    // we don't react to filter changes in this class, so this is a no-op
190	  }
191	
192	  // abstract FilterComponent.sortItemList
193	  sortItemList(
194	    listItems: TrafficListItem[],
195	    sortField: SortField<TrafficListItem>,
196	    isAscending: boolean
197	  ): TrafficListItem[] {
198	    return listItems.sort(isAscending ? sortField.compare : (a, b) => sortField.compare(b, a));
199	  }
200	
201	  // Helper used for Table to sort handlers based on index column == field
202	  onSort = (_event: React.MouseEvent, index: number, sortDirection: SortByDirection): void => {
203	    // Map the column index to the correct sortField index (currently ordered with the same indexes)
204	    let sortField = sortFields[index];
205	
206	    const isSortAscending = sortDirection === SortByDirection.asc;
207	
208	    this.updateSort(sortField, isSortAscending);
209	  };
210	
211	  trafficToListItems(trafficItems: TrafficItem[]): TrafficListItem[] {
212	    const listItems = trafficItems.map(ti => {
213	      let badge: PFBadgeType;
214	
215	      switch (ti.node.type) {
216	        case NodeType.APP:
217	          badge = PFBadges.App;
218	          break;
219	        case NodeType.SERVICE:
220	          badge = PFBadges.Service;
221	          break;
222	        default:
223	          badge = PFBadges.Workload;
224	      }
225	
226	      const item: TrafficListItem = {
227	        direction: ti.direction,
228	        badge: badge,
229	        node: ti.node,
230	        protocol: (ti.traffic.protocol ?? 'N/A').toUpperCase(),
231	        mTLS: ti.mTLS,
232	        healthStatus: this.getHealthStatus(ti),
233	        cluster: ti.node.cluster,
234	        ...this.getTraffic(ti.traffic)
235	      };
236	
237	      return item;
238	    });
239	
240	    return listItems;
241	  }
242	
243	  private getHealthStatus = (item: TrafficItem): ThresholdStatus => {
244	    const traffic = item.traffic;
245	
246	    if (traffic.protocol !== 'tcp' && hasProtocolTraffic(traffic)) {
247	      return getTrafficHealth(item, item.direction);
248	    }
249	
250	    return { value: 0, status: NA };
251	  };
252	
253	  private getTraffic = (traffic: ProtocolTraffic): { trafficPercentSuccess: string; trafficRate: string } => {
254	    let rps = '0';
255	    let percentError = '0';
256	    let unit = 'rps';
257	
258	    if (hasProtocolTraffic(traffic)) {
259	      switch (traffic.protocol) {
260	        case 'http':
261	          rps = traffic.rates.http;
262	          percentError = traffic.rates.httpPercentErr ?? '0';
263	          break;
264	        case 'grpc':
265	          rps = traffic.rates.grpc;
266	          percentError = traffic.rates.grpcPercentErr ?? '0';
267	          break;
268	        case 'tcp':
269	          rps = traffic.rates.tcp;
270	          break;
271	      }
272	    }
273	
274	    return {
275	      trafficRate: `${Number(rps).toFixed(2)}${unit}`,
276	      trafficPercentSuccess: `${(100 - Number(percentError)).toFixed(1)}%`
277	    };
278	  };
279	
280	  // Helper used to build the table content.
281	  rows = (direction: TrafficDirection): IRow[] => {
282	    const parentKiosk = isParentKiosk(this.props.kiosk);
283	
284	    return this.state.listItems
285	      .filter(i => i.direction === direction)
286	      .map((item, i) => {
287	        const name = item.node.name;
288	        const links = this.getLinks(item);
289	
290	        let irow: IRow = {
291	          cells: [
292	            <Tooltip
293	              key={`tt_status_${i}`}
294	              position={TooltipPosition.top}
295	              content={<>Traffic Status: {item.healthStatus.status.name}</>}
296	            >
297	              {createTooltipIcon(createIcon(item.healthStatus.status))}
298	            </Tooltip>,
299	            <>
300	              <PFBadge badge={item.badge} position={TooltipPosition.top} keyValue={`tt_badge_${i}`} />
301	              {!!links.detail ? (
302	                parentKiosk ? (
303	                  <Link
304	                    key={`link_d_${item.badge}_${name}`}
305	                    to=""
306	                    onClick={() => {
307	                      kioskContextMenuAction(links.detail);
308	                    }}
309	                  >
310	                    {name}
311	                  </Link>
312	                ) : (
313	                  <Link key={`link_d_${item.badge}_${name}`} to={links.detail}>
314	                    {name}
315	                  </Link>
316	                )
317	              ) : (
318	                name
319	              )}
320	            </>,
321	            <>{item.trafficRate}</>,
322	            <>{item.trafficPercentSuccess}</>,
323	            <>
324	              {item.protocol}
325	              <LockIcon mTLS={item.mTLS}></LockIcon>
326	            </>,
327	            <>
328	              {!!links.metrics &&
329	                (parentKiosk ? (
330	                  <Link
331	                    key={`link_m_${item.badge}_${name}`}
332	                    to=""
333	                    onClick={() => {
334	                      kioskContextMenuAction(links.metrics);
335	                    }}
336	                  >
337	                    View metrics
338	                  </Link>
339	                ) : (
340	                  <Link key={`link_m_${item.badge}_${name}`} to={links.metrics}>
341	                    View metrics
342	                  </Link>
343	                ))}
344	            </>
345	          ]
346	        };
347	
348	        if (isMultiCluster) {
349	          if (irow.cells) {
350	            irow.cells.splice(
351	              2,
352	              0,
353	              <>
354	                <PFBadge badge={PFBadges.Cluster} position={TooltipPosition.right} />
355	                {item.cluster}
356	              </>
357	            );
358	          }
359	        }
360	
361	        return irow;
362	      });
363	  };
364	
365	  private getLinks = (item: TrafficListItem): { detail: string; metrics: string } => {
366	    if (item.node.isInaccessible) {
367	      return { detail: '', metrics: '' };
368	    }
369	
370	    let detail = `/namespaces/${item.node.namespace}/${this.nodeTypeToType(item.node.type, true)}/${item.node.name}`;
371	
372	    if (item.node.cluster && isMultiCluster) {
373	      detail += `?clusterName=${item.node.cluster}`;
374	    }
375	
376	    const metricsDirection = item.direction === 'inbound' ? 'in_metrics' : 'out_metrics';
377	    const pathname = location.getPathname();
378	    let metrics = `${pathname}${getParamsSeparator(pathname)}tab=${metricsDirection}`;
379	
380	    switch (item.node.type) {
381	      case NodeType.APP:
382	        // All metrics tabs can filter by remote app. No need to switch context.
383	        const side = item.direction === 'inbound' ? 'source' : 'destination';
384	        metrics += `&${URLParam.BY_LABELS}=${encodeURIComponent(`${side}_canonical_service=${item.node.name}`)}`;
385	        break;
386	      case NodeType.SERVICE:
387	        if (item.node.isServiceEntry) {
388	          // Service Entries should be only destination nodes. So, don't build a link if direction is inbound.
389	          if (item.direction !== 'inbound' && item.node.destServices && item.node.destServices.length > 0) {
390	            const svcHosts = item.node.destServices.map(item => item.name).join(',');
391	            metrics += `&${URLParam.BY_LABELS}=${encodeURIComponent(`destination_service_name=${svcHosts}`)}`;
392	          } else {
393	            metrics = '';
394	          }
395	        } else {
396	          // Filter by remote service only available in the Outbound Metrics tab. For inbound traffic,
397	          // switch context to the service details page.
398	          if (item.direction === 'outbound') {
399	            metrics += `&${URLParam.BY_LABELS}=${encodeURIComponent(`destination_service_name=${item.node.name}`)}`;
400	          } else {
401	            // Services have only one metrics tab.
402	            metrics = `${detail}${getParamsSeparator(detail)}tab=metrics`;
403	          }
404	        }
405	        break;
406	      case NodeType.WORKLOAD:
407	        // No filters available for workloads. Context switch is mandatory.
408	
409	        // Since this will switch context (i.e. will redirect the user to the workload details page),
410	        // user is redirected to the "opposite" metrics. When looking at certain item, if traffic is *inbound*
411	        // from a certain workload, that traffic is reflected in the *outbound* metrics of the workload (and vice-versa).
412	        const inverseMetricsDirection = item.direction === 'inbound' ? 'out_metrics' : 'in_metrics';
413	        metrics = `${detail}${getParamsSeparator(detail)}tab=${inverseMetricsDirection}`;
414	        break;
415	      default:
416	        metrics = '';
417	    }
418	
419	    return { detail: detail, metrics: metrics };
420	  };
421	
422	  private nodeTypeToType = (type: NodeType, isURL?: boolean): string => {
423	    switch (type) {
424	      case NodeType.APP:
425	        return isURL ? 'applications' : 'Application';
426	      case NodeType.SERVICE:
427	        return isURL ? 'services' : 'Service';
428	      default:
429	        return isURL ? 'workloads' : 'Workload';
430	    }
431	  };
432	}
433	
434	const mapStateToProps = (state: KialiAppState): ReduxProps => {
435	  return {
436	    kiosk: state.globalState.kiosk
437	  };
438	};
439	
440	export const TrafficListComponent = connect(mapStateToProps)(TrafficList);

