230	        protocol: (ti.traffic.protocol ?? 'N/A').toUpperCase(),
231	        mTLS: ti.mTLS,
232	        healthStatus: this.getHealthStatus(ti),
233	        cluster: ti.node.cluster,
234	        ...this.getTraffic(ti.traffic)
235	      };
236	
237	      return item;
238	    });
239	
240	    return listItems;
241	  }
