253	  private getTraffic = (traffic: ProtocolTraffic): { trafficPercentSuccess: string; trafficRate: string } => {
254	    let rps = '0';
255	    let percentError = '0';
256	    let unit = 'rps';
257	
258	    if (hasProtocolTraffic(traffic)) {
259	      switch (traffic.protocol) {
260	        case 'http':
261	          rps = traffic.rates.http;
262	          percentError = traffic.rates.httpPercentErr ?? '0';
263	          break;
264	        case 'grpc':
265	          rps = traffic.rates.grpc;
266	          percentError = traffic.rates.grpcPercentErr ?? '0';
267	          break;
268	        case 'tcp':
269	          rps = traffic.rates.tcp;
270	          break;
271	      }
272	    }
273	
274	    return {
275	      trafficRate: `${Number(rps).toFixed(2)}${unit}`,
276	      trafficPercentSuccess: `${(100 - Number(percentError)).toFixed(1)}%`
277	    };
278	  };
